arguments.sparql_query:
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX owl:  <http://www.w3.org/2002/07/owl#>
SELECT ?cls ?label WHERE {
  ?cls a owl:Class ;
       rdfs:subClassOf <https://www.purl.org/futuram#Component> .
  OPTIONAL { ?cls rdfs:label ?label }
  FILTER(NOT EXISTS {
    ?cls rdfs:subClassOf ?mid .
    ?mid rdfs:subClassOf <https://www.purl.org/futuram#Component> .
    FILTER(?mid != <https://www.purl.org/futuram#Component>)
  })
} ORDER BY ?cls

PREFIX fq: <https://www.purl.org/futuram/query#>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX owl: <http://www.w3.org/2002/07/owl#>
SELECT ?cls ?label WHERE {
  ?cls a owl:Class .
  OPTIONAL { ?cls rdfs:label ?label }
  FILTER(
    CONTAINS(LCASE(STR(?label)), "electronic") ||
    CONTAINS(LCASE(STR(?label)), "cable") ||
    CONTAINS(LCASE(STR(?label)), "wiring")
  )
} ORDER BY ?cls

