PREFIX fq:      <https://www.purl.org/futuram/query#>
PREFIX futuram: <https://www.purl.org/futuram#>
PREFIX rdf:     <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
PREFIX rdfs:    <http://www.w3.org/2000/01/rdf-schema#>
SELECT ?node ?comp ?itemMass ?frac ?relUnc
       (?frac * ?itemMass AS ?kg)
       (?relUnc * ?frac * ?itemMass AS ?kgUnc)
WHERE {
  ?node futuram:partOf <https://www.purl.org/futuram#V0301030103_Y2025> ;
        rdf:type/rdfs:subClassOf* ?comp ;
        fq:itemMass ?itemMass ;
        fq:contains [ fq:constituent <https://www.purl.org/futuram#Copper> ;
                      fq:amount ?frac ;
                      fq:relativeUncertainty ?relUnc ] .
  FILTER(?comp IN (<https://www.purl.org/futuram#elvElectricMotor>,
                   <https://www.purl.org/futuram#elvEmbeddedElectronics>,
                   <https://www.purl.org/futuram#elvEmbeddedElectronicsCables>,
                   <https://www.purl.org/futuram#elvEmbeddedElectronicsControllers>,
                   <https://www.purl.org/futuram#elvEmbeddedElectronicsActuators>,
                   <https://www.purl.org/futuram#elvEmbeddedElectronicsHeadlights>,
                   <https://www.purl.org/futuram#elvPowerElectronics>))
}
ORDER BY ?comp ?node

