arguments.sparql_query:
PREFIX fq:      <https://www.purl.org/futuram/query#>
PREFIX futuram: <https://www.purl.org/futuram#>
PREFIX rdf:     <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
PREFIX rdfs:    <http://www.w3.org/2000/01/rdf-schema#>
PREFIX owl:     <http://www.w3.org/2002/07/owl#>

# Find the direct subclasses of Component, and for each, its year's scope node scoped to V0301030103_Y2025
SELECT ?node ?comp ?label (?frac * ?itemMass AS ?kg) (?relUnc * ?frac * ?itemMass AS ?kgUnc) WHERE {
  # Get the direct component subclasses
  ?comp rdfs:subClassOf <https://www.purl.org/futuram#Component> .
  FILTER NOT EXISTS {
    ?comp rdfs:subClassOf ?mid .
    ?mid rdfs:subClassOf <https://www.purl.org/futuram#Component> .
    FILTER(?mid != <https://www.purl.org/futuram#Component>)
  }
  # Resolve scope node typed to that component class (EXACT type)
  ?node futuram:partOf <https://www.purl.org/futuram#V0301030103_Y2025> ;
        rdf:type ?comp ;
        fq:itemMass ?itemMass ;
        fq:contains [ fq:constituent <https://www.purl.org/futuram#Copper> ;
                      fq:amount ?frac ;
                      fq:relativeUncertainty ?relUnc ] .
  OPTIONAL { ?comp rdfs:label ?label }
}
ORDER BY DESC(?kg)

