PREFIX fq: <https://www.purl.org/futuram/query#>
PREFIX futuram: <https://www.purl.org/futuram#>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX rdf: <http://www.w3.org/1999/02/22-rdf-syntax-ns#>

# Find direct subclasses of Component (the level-root) that have a scope node partOf the BEV 2025 segment C
# A "direct component" = rdfs:subClassOf Component but NOT rdfs:subClassOf any other rdfs:subClassOf of Component
SELECT ?key ?label WHERE {
  ?key rdfs:subClassOf <https://www.purl.org/futuram#Component> .
  ?node futuram:partOf <https://www.purl.org/futuram#V0301030103_Y2025> ;
        rdf:type ?key .
  OPTIONAL { ?key rdfs:label ?label }
  FILTER NOT EXISTS {
    ?key rdfs:subClassOf ?mid .
    ?mid rdfs:subClassOf <https://www.purl.org/futuram#Component> .
    FILTER(?mid != <https://www.purl.org/futuram#Component>)
  }
}
ORDER BY ?key

