arguments.sparql_query:
PREFIX fq: <https://www.purl.org/futuram/query#>
PREFIX futuram: <https://www.purl.org/futuram#>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX rdf: <http://www.w3.org/1999/02/22-rdf-syntax-ns#>

# For each direct component scope node of BEV 2025 segment C, pull Copper content
# Also restrict: constituents that are rdfs:subClassOf* Copper or named like pureCu_in_*
SELECT ?key ?label ?itemMass ?frac ?relUnc WHERE {
  ?node futuram:partOf <https://www.purl.org/futuram#V0301030103_Y2025> ;
        rdf:type ?key ;
        fq:itemMass ?itemMass ;
        fq:contains ?amount .
  ?amount fq:constituent ?cons ; fq:amount ?frac ; fq:relativeUncertainty ?relUnc .
  FILTER(?cons = <https://www.purl.org/futuram#Copper> || ?cons = <https://www.purl.org/futuram#pureCu_in_elvElectricMotor> || ?cons = <https://www.purl.org/futuram#pureCu_in_elvEmbeddedElectronicsCables> || CONTAINS(LCASE(STR(?cons)), "copper") || CONTAINS(LCASE(STR(?cons)), "cu"))
  ?key rdfs:subClassOf <https://www.purl.org/futuram#Component> .
  FILTER NOT EXISTS {
    ?key rdfs:subClassOf ?mid .
    ?mid rdfs:subClassOf <https://www.purl.org/futuram#Component> .
    FILTER(?mid != <https://www.purl.org/futuram#Component>)
  }
  OPTIONAL { ?key rdfs:label ?label }
}
ORDER BY ?key

