PREFIX fq: <https://www.purl.org/futuram/query#>
PREFIX futuram: <https://www.purl.org/futuram#>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX rdf: <http://www.w3.org/1999/02/22-rdf-syntax-ns#>

# Get Copper mass + uncertainty for every component scope node of BEV 2025 segment C
# Find all components at all levels with scope node in this whole, then filter to Copper
SELECT ?key ?label (?itemMass * ?frac AS ?kgCu) (?itemMass * ?frac * ?relUnc AS ?kgUnc) WHERE {
  ?node futuram:partOf <https://www.purl.org/futuram#V0301030103_Y2025> ;
        rdf:type ?key ;
        fq:itemMass ?itemMass ;
        fq:contains [ fq:constituent <https://www.purl.org/futuram#Copper> ; fq:amount ?frac ; fq:relativeUncertainty ?relUnc ] .
  ?key rdfs:subClassOf+ <https://www.purl.org/futuram#Component> .
  OPTIONAL { ?key rdfs:label ?label }
}
ORDER BY DESC(?kgCu)

