arguments.sparql_query:
PREFIX fq:      <https://www.purl.org/futuram/query#>
PREFIX futuram: <https://www.purl.org/futuram#>
PREFIX rdf:     <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
PREFIX rdfs:    <http://www.w3.org/2000/01/rdf-schema#>
SELECT ?node ?key ?m (?f * ?m AS ?kg) (?relUnc * ?f * ?m AS ?kgUnc)
WHERE {
  ?node futuram:partOf futuram:V0301030103_Y2025 ;
        rdf:type ?key ;
        fq:itemMass ?m ;
        fq:contains [ fq:constituent futuram:Copper ; fq:amount ?f ; fq:relativeUncertainty ?relUnc ] .
  ?key rdfs:subClassOf futuram:Component .
  FILTER NOT EXISTS {
    ?key rdfs:subClassOf ?mid .
    ?mid rdfs:subClassOf futuram:Component .
    FILTER(?mid != futuram:Component)
  }
}
ORDER BY DESC(?kg)

